+describe("Feishu reply fallback for withdrawn/deleted targets", () => {
+  const replyMock = vi.fn();
+  const createMock = vi.fn();
+
+  beforeEach(() => {
+    vi.clearAllMocks();
+    resolveFeishuSendTargetMock.mockReturnValue({
+      client: {
+        im: {
